// Generates src/react/federation-flight-client-source.ts which embeds a
// pre-built copy of react-server-dom-webpack/client.browser as a string
// constant. This runs BEFORE tsc so the generated file compiles normally.
//
// Why this is needed: RSC uses a binary protocol called Flight to serialize
// React element trees into a stream. Decoding Flight streams requires a
// Flight client, which is not part of react or react-dom. It lives in a
// separate package (react-server-dom-webpack). In a normal spiceflow app,
// @vitejs/plugin-rsc provides the Flight client automatically. But standalone
// federation consumers (Next.js, plain SPA) don't use that plugin, so they
// have no Flight client. This script pre-bundles the Flight client and embeds
// it as a string constant so setupFederationConsumer() can load it at runtime
// via a blob URL, without requiring the consumer to install or configure
// react-server-dom-webpack themselves.
//
// The pre-built copy has two key transformations:
// 1. __webpack_require__ → globalThis.__vite_rsc_require__ (same name as
//    vite-rsc uses, so both Vite and non-Vite hosts share one global)
// 2. A require() shim backed by globalThis.__FEDERATION_MODULES__ for
//    resolving react/react-dom at module init time
import { build } from 'esbuild'
import { writeFileSync } from 'fs'
import { dirname, resolve } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const outTs = resolve(__dirname, '../src/react/federation-flight-client-source.ts')

const banner = `
var require = (id) => {
  var m = globalThis.__FEDERATION_MODULES__?.[id];
  if (m) return m;
  throw new Error("[federation-flight-client] Module not found: " + id + ". Populate globalThis.__FEDERATION_MODULES__ before loading.");
};
`.trim()

const result = await build({
  stdin: {
    contents: [
      `import mod from 'react-server-dom-webpack/client.browser';`,
      `export const createFromReadableStream = mod.createFromReadableStream;`,
      `export const createFromFetch = mod.createFromFetch;`,
      `export default mod;`,
    ].join('\n'),
    resolveDir: resolve(__dirname, '..'),
    loader: 'js',
  },
  bundle: true,
  format: 'esm',
  write: false,
  external: ['react', 'react-dom'],
  platform: 'browser',
  define: {
    __webpack_require__: 'globalThis.__vite_rsc_require__',
  },
  banner: { js: banner },
  minify: false,
})

const source = result.outputFiles[0].text

const ts = [
  '// Auto-generated by scripts/build-flight-client.ts — do not edit.',
  '// Pre-built react-server-dom-webpack/client.browser with __webpack_require__',
  '// replaced by globalThis.__vite_rsc_require__ and a require() shim for React.',
  `export const FLIGHT_CLIENT_SOURCE = ${JSON.stringify(source)}`,
  '',
].join('\n')

writeFileSync(outTs, ts)
console.log(`Generated ${outTs} (${(source.length / 1024).toFixed(1)} KB)`)
